var e=[{id:`L8_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`빨리요! 이러다 놓치겠어요!`,JPN:`早く！　このままじゃ逃します！`,ENG:`Hurry up! We're gonna lose her!`,TWN:`快點！要被她給逃掉了！`},stage:{bg:`CITY_STREET_DISASTER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L9_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`아, 아뇨! 전 그냥 펠리세트를 데려오려고 한 건데……!`,JPN:`い、いいえ！　私はただフェリセットを連れて帰ろうと思って……！`,ENG:`Oh, that's not why I'm here! I'm here to bring you back...!`,TWN:`不，不是欸！我是來帶你回去的……！`},stage:{bg:`CITY_STREET_DISASTER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`빈손으로는 절대 안 돌아가요!`,JPN:`絶対手ぶらでは帰りません！`,ENG:`I won't go back empty-handed!`,TWN:`我絕對不會空手而回！`},stage:{bg:`CITY_STREET_DISASTER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`하, 하지만……!`,JPN:`で、でも……！`,ENG:`B-but...!`,TWN:`可是……！`},stage:{bg:`CITY_STREET_DISASTER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L16_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`따라붙은 건…… 둘뿐인가?`,JPN:`追ってきたのは……二人だけ？`,ENG:`Are they... the only two on my tail?`,TWN:`追上來的……就只有二個人？`},stage:{bg:`CITY_STREET_DISASTER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`하아, 하아, 하아……!`,JPN:`はぁ、はぁ、はぁ……！`,ENG:`*Huff*... *Huff*... *Huff*...!`,TWN:`呼呼，呼呼……！`},stage:{bg:`GAUNTLET`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`펠리세트! 진정해요! 너무 흥분하면…….`,JPN:`フェリセット！　落ち着いてください！　あまり興奮すると……`,ENG:`Félicette! Calm down! If you lose your temper, then–`,TWN:`費莉塞特！你冷靜一點！不要那麼激動……`},stage:{bg:`GAUNTLET`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`피해요!! 노엘!!`,JPN:`避けて！！　ノエル！！`,ENG:`Watch out!! Noelle!!`,TWN:`躲開！！洛艾兒！！`},stage:{bg:`GAUNTLET`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`},{id:`L27_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`으앗!?`,JPN:`わわっ！？`,ENG:`Ack?!`,TWN:`啊啊！？`},stage:{bg:`GAUNTLET`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`},{id:`L28_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`노엘! 제 뒤로 오세요! 빨리!`,JPN:`ノエル！　私の後ろへ下がってください！　早く！`,ENG:`Noelle! Get behind me! Quick!`,TWN:`洛艾兒！到我後面！快！`},stage:{bg:`GAUNTLET`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`그 방패, 평범한 물건은 아닌가 보네. 보통은 방패와 함께 너도 잘렸을 텐데.`,JPN:`その盾、ただの盾ではないようね。普通なら盾と共に君も斬られていたはずだから。`,ENG:`That is no ordinary shield, I assume. For you would have been cut in half along with it if it were.`,TWN:`那個盾牌似乎非同一般？正常來說，你應該會跟盾牌一起裂成二半才對。`},stage:{bg:`GAUNTLET`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02`},{id:`L31_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`……하지만 겨우 둘이서 쫓아 온 건, 후회하게 될 거야.`,JPN:`……でも、たった二人で追ってきたことを後悔するのね。`,ENG:`...However, you will regret coming after me with just the two of you.`,TWN:`……不過，竟然才派二個人來追我，你們會後悔的。`},stage:{bg:`GAUNTLET`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};